/*
 * remquo() test harness — prints (x_hex, y_hex, rem_hex, quo) quads.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifdef EN_PERF
static volatile double g_acc;

static void emit(double x, double y)
{
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    volatile double vy = y;
    int quo;
    g_acc += remquo(vx, vy, &quo);
}
#else
static void emit(double x, double y)
{
    int quo;
    double rem = remquo(x, y, &quo);
    printf("%016llx %016llx %016llx %d\n", (unsigned long long)d2u(x), (unsigned long long)d2u(y), (unsigned long long)d2u(rem), quo);
}

static void emit_u(uint64_t x_bits, uint64_t y_bits)
{
    emit(u2d(x_bits), u2d(y_bits));
}
#endif

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values for x, y=1.0 (7) --- */
    emit(0.0, 1.0);                                                            /* +0 / 1 */
    emit(-0.0, 1.0);                                                           /* -0 / 1 */
#ifdef EN_PERF
    emit(u2d(0x7ff8000000000000ULL), 1.0);  /* qNaN / 1.0 */
    emit(u2d(0x7ff0000000000001ULL), 1.0);  /* sNaN / 1.0 */
    emit(u2d(0xfff8000000000000ULL), 1.0);  /* -qNaN / 1.0 */
    emit(u2d(0x7ff0000000000000ULL), 1.0);  /* +Inf / 1.0 -> NaN */
    emit(u2d(0xfff0000000000000ULL), 1.0);  /* -Inf / 1.0 -> NaN */
#else
    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL);  /* qNaN / 1.0 */
    emit_u(0x7ff0000000000001ULL, 0x3ff0000000000000ULL);  /* sNaN / 1.0 */
    emit_u(0xfff8000000000000ULL, 0x3ff0000000000000ULL);  /* -qNaN / 1.0 */
    emit_u(0x7ff0000000000000ULL, 0x3ff0000000000000ULL);  /* +Inf / 1.0 -> NaN */
    emit_u(0xfff0000000000000ULL, 0x3ff0000000000000ULL);  /* -Inf / 1.0 -> NaN */
#endif

    /* --- Section 2: Special IEEE 754 values for y, x=1.0 (5) --- */
    emit(1.0, 0.0);                                                            /* 1.0 / +0 -> NaN */
#ifdef EN_PERF
    emit(1.0, u2d(0x7ff8000000000000ULL));  /* 1.0 / qNaN */
    emit(1.0, u2d(0x7ff0000000000001ULL));  /* 1.0 / sNaN */
    emit(1.0, u2d(0x7ff0000000000000ULL));  /* 1.0 / +Inf -> 1.0 */
    emit(1.0, u2d(0xfff0000000000000ULL));  /* 1.0 / -Inf -> 1.0 */
#else
    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL);  /* 1.0 / qNaN */
    emit_u(0x3ff0000000000000ULL, 0x7ff0000000000001ULL);  /* 1.0 / sNaN */
    emit_u(0x3ff0000000000000ULL, 0x7ff0000000000000ULL);  /* 1.0 / +Inf -> 1.0 */
    emit_u(0x3ff0000000000000ULL, 0xfff0000000000000ULL);  /* 1.0 / -Inf -> 1.0 */
#endif

    /* --- Section 3: Subnormal x values with y=1.0 (6) --- */
#ifdef EN_PERF
    emit(u2d(0x0000000000000001ULL), 1.0);  /* min positive subnormal: 2^-1074 */
    emit(u2d(0x8000000000000001ULL), 1.0);  /* min negative subnormal */
    emit(u2d(0x0008000000000000ULL), 1.0);  /* mid positive subnormal */
    emit(u2d(0x8008000000000000ULL), 1.0);  /* mid negative subnormal */
    emit(u2d(0x000fffffffffffffULL), 1.0);  /* max subnormal: just below DBL_MIN */
    emit(u2d(0x800fffffffffffffULL), 1.0);  /* max negative subnormal */
#else
    emit_u(0x0000000000000001ULL, 0x3ff0000000000000ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL, 0x3ff0000000000000ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL, 0x3ff0000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL, 0x3ff0000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL, 0x3ff0000000000000ULL);  /* max subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL, 0x3ff0000000000000ULL);  /* max negative subnormal */
#endif

    /* --- Section 4: Subnormal y values with x=1.0 (4) --- */
#ifdef EN_PERF
    emit(1.0, u2d(0x0000000000000001ULL));  /* 1.0 / min positive subnormal */
    emit(1.0, u2d(0x0008000000000000ULL));  /* 1.0 / mid subnormal */
    emit(1.0, u2d(0x000fffffffffffffULL));  /* 1.0 / max subnormal */
    emit(1.0, u2d(0x8000000000000001ULL));  /* 1.0 / min negative subnormal */
#else
    emit_u(0x3ff0000000000000ULL, 0x0000000000000001ULL);  /* 1.0 / min positive subnormal */
    emit_u(0x3ff0000000000000ULL, 0x0008000000000000ULL);  /* 1.0 / mid subnormal */
    emit_u(0x3ff0000000000000ULL, 0x000fffffffffffffULL);  /* 1.0 / max subnormal */
    emit_u(0x3ff0000000000000ULL, 0x8000000000000001ULL);  /* 1.0 / min negative subnormal */
#endif

    /* --- Section 5: Normal boundary values (6) --- */
    emit(DBL_MIN, 1.0);                                                        /* smallest normal positive */
    emit(-DBL_MIN, 1.0);                                                       /* smallest normal negative */
#ifdef EN_PERF
    emit(u2d(0x0010000000000001ULL), 1.0);  /* one ULP above DBL_MIN */
#else
    emit_u(0x0010000000000001ULL, 0x3ff0000000000000ULL);  /* one ULP above DBL_MIN */
#endif
    emit(DBL_MAX, 1.0e100);                                                    /* DBL_MAX with large divisor */
    emit(-DBL_MAX, 1.0e100);                                                   /* -DBL_MAX with large divisor */
    emit(1.0, DBL_MIN);                                                        /* 1.0 / DBL_MIN */

    /* --- Section 6: Basic arithmetic cases (10) --- */
    emit(5.0, 2.0);     /* 5 mod 2 -> -1, quo=2 (nearest int quotient) */
    emit(5.5, 2.5);     /* 5.5 mod 2.5 -> 0.5, quo=2 */
    emit(-5.0, 2.0);    /* -5 mod 2 -> 1, quo=-2 */
    emit(5.0, -2.0);    /* 5 mod -2 -> -1, quo=-2 */
    emit(-5.0, -2.0);   /* -5 mod -2 -> 1, quo=2 */
    emit(7.0, 2.5);     /* 7 mod 2.5 -> -0.5, quo=3 */
    emit(10.0, 3.0);    /* 10 mod 3 -> 1, quo=3 */
    emit(22.0, 7.0);    /* 22 mod 7 -> 1, quo=3 */
    emit(100.0, 30.0);  /* 100 mod 30 -> 10, quo=3 */
    emit(3.0, 2.0);     /* 3 mod 2 -> -1, quo=2 */

    /* --- Section 7: Exact divisibility (8) --- */
    emit(10.0, 5.0);    /* x = 2*y exactly, quo=2, rem=0 */
    emit(15.0, 5.0);    /* x = 3*y exactly, quo=3, rem=0 */
    emit(100.0, 10.0);  /* x = 10*y exactly, quo=10, rem=0 */
    emit(-20.0, 4.0);   /* negative exact, quo=-5, rem=0 */
    emit(0.5, 0.5);     /* x = y, quo=1, rem=0 */
    emit(1.5, 0.5);     /* x = 3*y, quo=3, rem=0 */
    emit(1.0, 1.0);     /* x = y = 1, quo=1, rem=0 */
    emit(-1.0, 1.0);    /* -x = y, quo=-1, rem=0 */

    /* --- Section 8: Near-half cases - quotient rounding boundary (10) --- */
    emit(2.5, 2.0);     /* x/y = 1.25 -> quo=1, rem=0.5 */
    emit(3.5, 2.0);     /* x/y = 1.75 -> quo=2, rem=-0.5 */
    emit(4.5, 2.0);     /* x/y = 2.25 -> quo=2, rem=0.5 */
    emit(-2.5, 2.0);    /* x/y = -1.25 -> quo=-1, rem=-0.5 */
    emit(-3.5, 2.0);    /* x/y = -1.75 -> quo=-2, rem=0.5 */
    emit(1.5, 1.0);     /* x/y = 1.5 exactly half -> round-to-even quo=2, rem=-0.5 */
    emit(2.5, 1.0);     /* x/y = 2.5 exactly half -> round-to-even quo=2 or 3 */
    emit(0.75, 0.5);    /* x/y = 1.5 -> quo=2, rem=-0.25 */
    emit(1.25, 0.5);    /* x/y = 2.5 -> quo=2 or 3 */
    emit(-1.5, 1.0);    /* x/y = -1.5 -> quo=-2, rem=0.5 */

    /* --- Section 9: Large magnitude inputs (8) --- */
    emit(1.0e100, 1.0e50);
    emit(1.0e200, 1.0e100);
    emit(-1.0e100, 1.0e50);
    emit(1.0e50, 1.0e100);   /* x < y, rem=x */
    emit(1.0e15, 3.0);       /* large x, small y */
    emit(1.0e16, 7.0);
    emit(1.0e17, 11.0);
    emit(1.23456789012345e15, 1.0);  /* large with fractional bits */

    /* --- Section 10: Mixed sign and near-zero divisor (8) --- */
    emit(1.0e-100, 1.0e-50);   /* both tiny, x < y, rem=x */
    emit(1.0e-200, 1.0e-100);  /* very tiny */
    emit(1.0, 1.0e-10);        /* large quotient */
    emit(-1.0, 1.0e-10);       /* large negative quotient */
    emit(1.0, 1.0e10);         /* x << y -> rem = x */
    emit(-1.0, 1.0e10);        /* negative x << y -> rem = x */
    emit(355.0, 113.0);        /* near-pi ratio */
    emit(-355.0, 113.0);       /* negative near-pi ratio */

    /* --- Section 11: ULP neighbor cases near key values (8) --- */
#ifdef EN_PERF
    emit(u2d(0x3fefffffffffffffULL), 1.0);  /* one ULP below 1.0 */
    emit(u2d(0x3ff0000000000001ULL), 1.0);  /* one ULP above 1.0 */
    emit(1.0, u2d(0x3fefffffffffffffULL));  /* 1.0 / one ULP below 1.0 */
    emit(1.0, u2d(0x3ff0000000000001ULL));  /* 1.0 / one ULP above 1.0 */
    emit(2.0, 1.0);
    emit(u2d(0x4000000000000001ULL), 1.0);  /* one ULP above 2.0 */
    emit(u2d(0x3fffffffffffffffULL), 1.0);  /* one ULP below 2.0 */
    emit(1.0, 2.0);
#else
    emit_u(0x3fefffffffffffffULL, 0x3ff0000000000000ULL);  /* one ULP below 1.0 / 1.0 */
    emit_u(0x3ff0000000000001ULL, 0x3ff0000000000000ULL);  /* one ULP above 1.0 / 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x3fefffffffffffffULL);  /* 1.0 / one ULP below 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x3ff0000000000001ULL);  /* 1.0 / one ULP above 1.0 */
    emit_u(0x4000000000000000ULL, 0x3ff0000000000000ULL);  /* 2.0 / 1.0 */
    emit_u(0x4000000000000001ULL, 0x3ff0000000000000ULL);  /* one ULP above 2.0 / 1.0 */
    emit_u(0x3fffffffffffffffULL, 0x3ff0000000000000ULL);  /* one ULP below 2.0 / 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x4000000000000000ULL);  /* 1.0 / 2.0 -> rem=1.0 */
#endif

    /* --- Section 12: Mathematical constants as inputs (10) --- */
#ifdef EN_PERF
    emit(u2d(0x400921fb54442d18ULL), 1.0);                               /* pi / 1.0 */
    emit(u2d(0x400921fb54442d18ULL), 2.0);                               /* pi / 2.0 */
    emit(u2d(0x400921fb54442d18ULL), u2d(0x400921fb54442d18ULL));        /* pi / pi */
    emit(u2d(0x3ff921fb54442d18ULL), 1.0);                               /* pi/2 / 1.0 */
    emit(u2d(0x3fe62e42fefa39efULL), 1.0);                               /* ln2 / 1.0 */
    emit(u2d(0x4005bf0a8b145769ULL), 1.0);                               /* e / 1.0 */
    emit(u2d(0x4005bf0a8b145769ULL), 2.0);                               /* e / 2.0 */
    emit(u2d(0x400921fb54442d18ULL), u2d(0x3fe62e42fefa39efULL));        /* pi / ln2 */
    emit(u2d(0xc00921fb54442d18ULL), 1.0);                               /* -pi / 1.0 */
    emit(u2d(0xbff921fb54442d18ULL), 1.0);                               /* -pi/2 / 1.0 */
#else
    emit_u(0x400921fb54442d18ULL, 0x3ff0000000000000ULL);  /* pi / 1.0 */
    emit_u(0x400921fb54442d18ULL, 0x4000000000000000ULL);  /* pi / 2.0 -> rem=pi-2 */
    emit_u(0x400921fb54442d18ULL, 0x400921fb54442d18ULL);  /* pi / pi -> rem=0 */
    emit_u(0x3ff921fb54442d18ULL, 0x3ff0000000000000ULL);  /* pi/2 / 1.0 */
    emit_u(0x3fe62e42fefa39efULL, 0x3ff0000000000000ULL);  /* ln2 / 1.0 */
    emit_u(0x4005bf0a8b145769ULL, 0x3ff0000000000000ULL);  /* e / 1.0 */
    emit_u(0x4005bf0a8b145769ULL, 0x4000000000000000ULL);  /* e / 2.0 */
    emit_u(0x400921fb54442d18ULL, 0x3fe62e42fefa39efULL);  /* pi / ln2 */
    emit_u(0xc00921fb54442d18ULL, 0x3ff0000000000000ULL);  /* -pi / 1.0 */
    emit_u(0xbff921fb54442d18ULL, 0x3ff0000000000000ULL);  /* -pi/2 / 1.0 */
#endif

    /* --- Section 13: x < y cases (half-interval, rem=x) (10) --- */
    emit(0.1, 1.0);     /* x < y/2, rem=x */
    emit(0.4, 1.0);     /* x < y/2, rem=x */
    emit(0.5, 1.0);     /* x = y/2 exactly */
    emit(-0.1, 1.0);    /* negative x < y/2 */
    emit(-0.4, 1.0);    /* negative x < y/2 */
    emit(-0.5, 1.0);    /* -x = y/2 exactly */
    emit(0.25, 1.0);    /* quarter */
    emit(0.75, 1.0);    /* three-quarters -> rounds to nearest */
    emit(-0.75, 1.0);   /* negative three-quarters */
    emit(0.0, 0.5);     /* 0 / 0.5 -> rem=0 */
}

/* ------------------------------------------------------------------ */

/* 7. Sweep through various divisors */
#ifndef EN_PERF
static void test_sweep(void)
{
    double divisors[] = { 0.5, 1.0, 1.5, 2.0, 2.5, 3.0, 3.5, 4.0 };
    int n = sizeof(divisors) / sizeof(divisors[0]);
    for (int i = 0; i < n; i++) {
        emit(10.0, divisors[i]);
        emit(-10.0, divisors[i]);
    }
}

/* 8. Sample across exponent range */
static void test_exhaustive_small(void)
{
    static const uint64_t vals[] = {
        0x0000000000000000ULL, /* 0.0 */
        0x3fc0000000000000ULL, /* 0.125 */
        0x3fd0000000000000ULL, /* 0.25 */
        0x3fe0000000000000ULL, /* 0.5 */
        0x3fe8000000000000ULL, /* 0.75 */
        0x3ff0000000000000ULL, /* 1.0 */
        0x4000000000000000ULL, /* 2.0 */
        0x4008000000000000ULL, /* 3.0 */
    };
    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
        emit_u(vals[i], 0x3ff0000000000000ULL);
}

/* 9. Random sweep: 15x20 grid = 300 cases */
static void test_random_300(void)
{
    int nx = 15, ny = 20;
    for (int i = 0; i < nx; i++) {
        double x = -10.0 + 20.0 * (double)i / (double)(nx - 1);
        for (int j = 0; j < ny; j++) {
            double y = 0.1 + 4.9 * (double)j / (double)(ny - 1);
            emit(x, y);
        }
    }
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
    test_random_300();
#endif
    return 0;
}
